import os

def delete_uploaded_file(filename, uploads_dir="uploads"):
    if not isinstance(filename, str) or not filename:
        return False

    safe_name = os.path.basename(filename)
    file_path = os.path.abspath(os.path.join(uploads_dir, safe_name))
    uploads_root = os.path.abspath(uploads_dir)

    if not file_path.startswith(uploads_root + os.sep) and file_path != uploads_root:
        return False

    if not os.path.isfile(file_path):
        return False

    os.remove(file_path)
    return True